import { Component, OnInit, Input, OnDestroy, Output, EventEmitter } from '@angular/core';
import { Observable, Subscription } from 'rxjs';
import { Store } from '@ngxs/store';
import { filter, map } from 'rxjs/operators';

@Component({
  selector: 'app-listado-facturas',
  templateUrl: './listado-facturas.component.html',
  styleUrls: ['./listado-facturas.component.css']
})
export class ListadoFacturasComponent implements OnInit,OnDestroy {

  @Input() mostrarPagas:boolean=true
  @Output() seleccionRetorno = new EventEmitter(); 
  @Output() sinFacturasParaAbonar = new EventEmitter(); 

  facturasResumen$:Subscription
  
  rowData: any;
  columnDefs=[
    {headerName: 'Periodo', field: 'periodo', minWidth:100,headerCheckboxSelection: true, checkboxSelection: true, },
    {headerName: 'Factura', field: 'factura', width:100  },
    {headerName: 'Estado', field: 'estado', width:100  },
    {headerName: 'Total', field: 'total', width:100  }
  ];

  gridApi:any;
  gridColumnApi: any;

  constructor(private store:Store) { }

  ngOnInit(): void {

     this.facturasResumen$ = this.store.select(state => state.factura.facturasResumen).pipe(
      map(x=> x.filter(factura=> { return this.mostrarPagas?true: factura.estado=='Impaga'} ))      
      ).subscribe(
        facturas =>  {this.rowData = facturas; if(facturas.length==0){this.sinFacturasParaAbonar.emit()} }       
    ) 

    
  }

  onGridReady(params) {
    this.gridApi = params.api;
    this.gridColumnApi = params.columnApi;
  }

  onSelectionChanged(event){
  this.seleccionRetorno.emit(this.gridApi.getSelectedRows())
  }

  ngOnDestroy(){
    this.facturasResumen$.unsubscribe()
  }

}
