import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import {ClienteHomeComponent} from './cliente-home.component'
import { Routes, RouterModule } from '@angular/router';
import { UpdateClienteComponent } from './update-cliente/update-cliente.component';
import {UtilsModule} from '../utils/utils.module'
import { ReactiveFormsModule } from '@angular/forms';
import { NotifierModule } from 'angular-notifier';

const routes: Routes = [
  {
    path:'',
    component:ClienteHomeComponent
  },{
    path:'actualizar',
    component:UpdateClienteComponent
  }
  
  
]

@NgModule({
  declarations: [ClienteHomeComponent, UpdateClienteComponent],
  imports: [
    CommonModule,
    RouterModule.forChild(routes),
    UtilsModule,
    ReactiveFormsModule,
    NotifierModule.withConfig( {  
      position: {
        horizontal: {
          position: 'right',
          distance: 12
        }},
        behaviour: {
          autoHide: 5000
        }
      }
   ),
  ]
})
export class ClienteHomeModule { }
