import { Component, OnInit } from '@angular/core';
import { FormGroup, FormBuilder, Validators, FormControl } from '@angular/forms';
import { Store } from '@ngxs/store';
import { Cliente } from 'src/app/store/cliente/model';
import { first } from 'rxjs/operators';
import {ClienteService} from '../services/cliente.service'
import { NotifierService } from 'angular-notifier';
import { GetCliente } from 'src/app/store/cliente/actions';
import { Router } from '@angular/router';

@Component({
  selector: 'app-update-cliente',
  templateUrl: './update-cliente.component.html',
  styleUrls: ['./update-cliente.component.css']
})
export class UpdateClienteComponent implements OnInit {

  updateForm: FormGroup;
  
  cliente:Cliente
  
  private readonly notifier: NotifierService;

  constructor(private formBuilder: FormBuilder,private store:Store, private cs:ClienteService,notifierService: NotifierService,private router: Router) { 
    this.notifier = notifierService;
  }

  ngOnInit(): void {
    this.store.select(state => state.cliente.cliente).pipe(first()).subscribe(
      clienteR=> {
        this.cliente = clienteR
        this.iniciarFormulario()
      }
    )
    
  }

  iniciarFormulario(){
    this.updateForm = this.formBuilder.group({
      email: [ this.cliente.email  , [Validators.required,this.esEmail]],           
      telefonoFijo:[ this.cliente.telefonoFijo,[Validators.minLength(0),Validators.maxLength(20)]  ],
      telefonoCelular:[ this.cliente.telefonoCelular ,[Validators.minLength(0),Validators.maxLength(20)]],
    });
  }

  actualizar(){
    this.cs.updateCliente(this.cliente.idSocio, this.updateForm.get('email').value,this.updateForm.get('telefonoFijo').value,this.updateForm.get('telefonoCelular').value).subscribe(
      _ => {
        this.notifier.notify( 'success', 'La información ha sido actualizada exitosamente!');
        this.store.dispatch(new GetCliente(this.cliente.idSocio))
        const self = this;
      setTimeout(function(){        
          self.router.navigate(['/home'])     
      }, 2000) 
      }
    )
  }


  esEmail(c: FormControl) {
    if (!c.value == false) {
      let exp = /[a-z0-9!#$%&'*+/=?^_`{|}~-]+(?:\.[a-z0-9!#$%&'*+/=?^_`{|}~-]+)*@(?:[a-z0-9](?:[a-z0-9-]*[a-z0-9])?\.)+[a-z0-9](?:[a-z0-9-]*[a-z0-9])?/;
      let re = new RegExp(exp);
      const comparacion = re.test(c.value);
      return comparacion ? null : {
        esEmail: {
          valid: false
        }
      }
    } else {
      return null;
    }

  }
  
}
