import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { environment } from 'src/environments/environment';
import { map } from 'rxjs/operators';
import { Observable } from 'rxjs';

@Injectable({
  providedIn: 'root'
})
export class ClienteService {

  constructor(private http: HttpClient) { }

  updateCliente(cliente:number,email:string,telefonoFijo:number,telefonoCelular:number):Observable<any>{        
    return this.http.put(`${environment.urlapi}cliente`,JSON.stringify({cliente,email,telefonoFijo,telefonoCelular})).pipe(
      map( (data:any) =>  data)
    )
  }

}
