import { Injectable } from '@angular/core';
import { environment } from 'src/environments/environment';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Observable } from 'rxjs';
import { Cliente } from './store/cliente/model';
import { map } from 'rxjs/operators';
import { FacturaResumen } from './store/factura/model';
import { ReciboSemestralResumen } from './store/recibo/model';

const httpOptions = {
  headers: new HttpHeaders({
    'Content-Type':  'application/json',
    'Access-Control-Allow-Headers': 'Content-Type',
    'Access-Control-Allow-Methods': 'GET,POST,OPTIONS,DELETE,PUT',
    'Access-Control-Allow-Origin': '*'       
  })
};


@Injectable({
  providedIn: 'root'
})


export class AppService {
  urlRest = environment;

  constructor(private http: HttpClient) { }

  
  getClienteDetalle(cliente:number):Observable<Cliente>{
    return this.http.get(`${this.urlRest.urlapi}cliente/${cliente}`).pipe(
      map( (data:Cliente) =>  data)
    )
   }

   getUltimaActualizacion():Observable<string>{
    return this.http.get(`${this.urlRest.urlapi}factura/ultima-actualizacion`).pipe(
      map( (data:string) =>  data)
    )
   }

   getFacturasDetalle(cliente:number):Observable<FacturaResumen[]>{
    return this.http.post(`${this.urlRest.urlapi}factura/resumen`,JSON.stringify({'cliente':cliente}),httpOptions).pipe(
      map((data:FacturaResumen[]) =>  data)
    )
   }

   getTotalFacturasPreviasAdeudadas(cliente:number):Observable<number>{
    return this.http.post(`${this.urlRest.urlapi}factura/previas/adeudadas`,JSON.stringify({'cliente':cliente}),httpOptions).pipe(
      map((data:number) =>  data)
    )
   }

  
   descargarFactura(factura:string): Observable<any>{

    return this.http.post(`${this.urlRest.urlapi}factura/descargar`,{'facturas':[factura]},
    {
      headers: new HttpHeaders({
        'Content-Type':  'application/json'    ,
        'Access-Control-Allow-Headers': 'Content-Type',
    'Access-Control-Allow-Methods': 'GET,POST,OPTIONS,DELETE,PUT',
    'Access-Control-Allow-Origin': '*'        
      }),    
      responseType: 'blob'
  }) 
    .pipe(
      map(response => {
        return response;
   })
    )
    
   }

   // Recibos Semestrales

   getReciboSemestralDetalle(cliente:number):Observable<ReciboSemestralResumen[]>{
    return this.http.post(`${this.urlRest.urlapi}recibo/resumen`,JSON.stringify({'cliente':cliente}),httpOptions).pipe(
      map((data:ReciboSemestralResumen[]) =>  data)
    )
   }

   descargarRecibo(recibo:string): Observable<any>{

    return this.http.post(`${this.urlRest.urlapi}recibo/descargar`,{'recibo':recibo},
    {
      headers: new HttpHeaders({
        'Content-Type':  'application/json',
        'Access-Control-Allow-Headers': 'Content-Type',
    'Access-Control-Allow-Methods': 'GET,POST,OPTIONS,DELETE,PUT',
    'Access-Control-Allow-Origin': '*'            
      }),    
      responseType: 'blob'
  }) 
    .pipe(
      map(response => {
        return response;
   })
    )
    
   }
}
