import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { BehaviorSubject, of } from 'rxjs';
import { Router } from '@angular/router';
import { Store } from '@ngxs/store';
import { Login } from '../store/login/actions';
import { tap, catchError } from 'rxjs/operators';
import { AuthState } from '../store/login/state';
import { GetCliente, ClearCliente } from '../store/cliente/actions';
import { GetFacturasResumen, GetUltimaActualizacion, GetTotalFacturasPreviasAdeudadas, ClearFacturas } from '../store/factura/actions';
import { GetReciboSemestralResumen, ClearReciboSemestral } from '../store/recibo/actions';
import { environment } from 'src/environments/environment';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.css']
})


export class LoginComponent implements OnInit {

  loginForm: FormGroup;
  submitted = false;

  public errorLogin= false;

  public sesionExpirada : boolean;

  private loadingSubject = new BehaviorSubject<boolean>(false);
  public loading$ = this.loadingSubject.asObservable();

  cliente = ''
  

  constructor(private formBuilder: FormBuilder,private router: Router,private store:Store) { }

  ngOnInit(): void {
    
    if(!environment.production){
      this.cliente = "00000100"      
    }

    this.initForm();
   
  }

  initForm() {

    this.loginForm = this.formBuilder.group({
      cliente: [ this.cliente  , [Validators.required,Validators.minLength(8),Validators.maxLength(8)]]           
    });
  }

  ingresar(){
    this.errorLogin = false;
    

   if (this.loginForm.invalid){
    this.errorLogin = true
   }else{
    this.loadingSubject.next(true);   

    this.store.dispatch(new Login({cliente:this.loginForm.value.cliente})).pipe(

      tap(_=> {this.loadingSubject.next(false); 
        this.initData();
        this.loadData();     
      this.router.navigate(['/'])}),
      
      catchError(err => {
        if (err === 'Unauthorized'){
          this.loadingSubject.next(false);
          this.errorLogin = true;
                 
        }
        return of(null)
      })
      ).subscribe();
   }

    
      
  }

  initData(){
    this.store.dispatch(new ClearCliente()) 
    this.store.dispatch(new ClearFacturas()) 
    this.store.dispatch(new ClearReciboSemestral()) 
  }

  loadData(){
    const id_cliente = this.store.selectSnapshot(AuthState.cliente);
    this.store.dispatch(new GetCliente(id_cliente))
    this.store.dispatch(new GetUltimaActualizacion())
    this.store.dispatch(new GetFacturasResumen(id_cliente))
    this.store.dispatch(new GetTotalFacturasPreviasAdeudadas(id_cliente))
    this.store.dispatch(new GetReciboSemestralResumen(id_cliente))
  }

}
