import { Component, OnInit } from '@angular/core';
import { Store } from '@ngxs/store';
import { ReciboSemestralResumen } from 'src/app/store/recibo/model';
import { map, first } from 'rxjs/operators';
import { FacturasService } from 'src/app/facturas/services/facturas.service';
import { Cliente } from 'src/app/store/cliente/model';
import { PagoFacturasClass } from 'src/app/facturas/pago-facturas/pago-facturas';
import { SetFormPayPerTics } from 'src/app/store/recibo/actions';
import { Router } from '@angular/router';
declare var $:any;

@Component({
  selector: 'app-pago-recibos-semestrales',
  templateUrl: './pago-recibos-semestrales.component.html',
  styleUrls: ['./pago-recibos-semestrales.component.css']
})
export class PagoRecibosSemestralesComponent implements OnInit {

  public recibosResumen: ReciboSemestralResumen[];
  public cliente: Cliente;
  totalACobrar:number
  estaProcesando:boolean=false

  constructor(private store:Store,private fs:FacturasService,private router: Router) { }

  ngOnInit(): void {
    this.store.select(state => state.reciboSemestral.reciboSemestralResumen).pipe(
      map(x=> x.filter(recibo=> { return recibo.estado=='Impaga'} ))      
      ).subscribe(
        recibos =>  {this.recibosResumen = recibos; this.totalACobrar = recibos[0].total}        
    ) 

    this.store.select(state => state.cliente.cliente).pipe(first()).subscribe(
      clienteR => this.cliente = clienteR
    )
  }

  pagar(){
     // solicitamos el mail en caso de no poseerlo antes de continuar  
     if(!this.cliente.email ||this.cliente.email == ''){
      $('#mailRequerido').modal('show')
    }else{
    this.estaProcesando = true
    //obtenemos la autorizacion a pay per tics
    this.fs.getAutorizacionEntidad().pipe(first()).subscribe(
      data => { this.generarPagoEtapa1(data.access_token)}
    )
  }
  }

  generarPagoEtapa1(autorizacion:string){
    // Debemos crear la nueva transaccion
    //1. Obtenemos el recibo
    let recibos= this.recibosResumen.map( (recibo:any)=>{ return {'factura_recibo':recibo.recibo,'total':recibo.total,'recargo':0,'ivaRecargo':0} } )
    
    //2. generamos la transaccion
    this.fs.nuevaTransaccion(recibos,this.cliente.idSocio,this.totalACobrar).pipe(first()).subscribe(
      numTransaccion =>{
        //generamos el pago
        this.generarPagoEtapa2(autorizacion,numTransaccion)       
      } 
    )
  }

  generarPagoEtapa2(autorizacion:string,numeroTransaccion:string){

    //utilizamos la clase PagoFacturasClass, ya que es la encargada de enviar el pago a pay per tic
    let pago:PagoFacturasClass = new PagoFacturasClass()
    pago.addIdPago(numeroTransaccion)
    this.recibosResumen.forEach(recibo=> pago.addDetalle(recibo.recibo,`Pago Recibo ${recibo.semestre}`,recibo.total))
    pago.addPagador(this.cliente.clienteNumero,this.cliente.nombre,this.cliente.email)
    
    // enviamos la consulta a pay per tics
     this.fs.getNuevoPago(autorizacion,pago).pipe(first()).subscribe(
      data=> {
        this.estaProcesando = false
        // seteamos la url con el formulario de retorno y la mostramos
        this.store.dispatch(new SetFormPayPerTics(data.form_url));
        this.router.navigate(['/recibos-semestrales/formulario/pagos'])
      } 
    ) 
    
  }

  cancelar(){
    $('#mailRequerido').modal('hide')
  }
  actualizarDatos(){
    $('#mailRequerido').modal('hide')
    this.router.navigate(['/home/actualizar'])
  }

}
